import React, { useState, useEffect, useRef } from 'react';
import { Copy, Wand2, Upload, Settings, Plus, Sparkles, FileText, TrendingUp, ChevronDown, ChevronRight, ToggleLeft, ToggleRight, Check, Terminal } from 'lucide-react';

// Terminal Workspace Component
function TerminalWorkspace({ editablePrompt, setEditablePrompt, sections, setSections }) {
  const [commandHistory, setCommandHistory] = useState(['> Welcome to Prompt Terminal! Type /help for commands']);
  const [currentCommand, setCurrentCommand] = useState('');
  const [commandMode, setCommandMode] = useState(false);
  const terminalRef = useRef(null);

  const commands = {
    '/help': () => [
      '> Available commands:',
      '  /analyze - Analyze current prompt structure',
      '  /subdivide [section] - Split section into parts', 
      '  /clear - Clear workspace',
      '  /paste - Paste clipboard content',
      '  /upload - Upload file reference',
      '  /merge - Merge all sections',
      '  /optimize - Run optimization analysis'
    ],
    '/analyze': () => {
      const filledSections = sections.filter(s => s.value.trim()).length;
      const totalChars = sections.reduce((acc, s) => acc + s.value.length, 0);
      return [
        '> Analyzing prompt structure...',
        `  ✓ Found ${sections.length} sections`,
        `  ✓ ${filledSections}/${sections.length} sections filled`,
        `  ✓ Total characters: ${totalChars}`,
        `  ✓ Optimization score: ${optimizationScore}%`,
        '  → Check live suggestions panel for improvements'
      ];
    },
    '/clear': () => {
      setEditablePrompt('');
      return ['> Workspace cleared'];
    },
    '/paste': () => ['> Ready to paste content. Use Ctrl+V in the text area above'],
    '/upload': () => ['> File upload ready. Drop files or use upload button'],
    '/merge': () => {
      const merged = sections
        .filter(s => s.value.trim())
        .map(s => `# ${s.label}\n${s.value}`)
        .join('\n\n');
      setEditablePrompt(merged);
      return ['> All sections merged into workspace'];
    },
    '/optimize': () => {
      // Trigger live suggestions for active section if available
      const activeSection = findSection(activeSectionId);
      if (activeSection && activeSection.value.length > 10) {
        generateLiveSuggestions(activeSection);
      }
      return [
        '> Running optimization scan...',
        `  ✓ Completeness: ${Math.round(scoreBreakdown.completeness || 0)}%`,
        `  ✓ Clarity: ${Math.round(scoreBreakdown.clarity || 0)}%`,  
        `  ✓ Structure: ${Math.round(scoreBreakdown.structure || 0)}%`,
        '  → Check live suggestions panel for AI improvements'
      ];
    }
  };

  const executeCommand = (cmd) => {
    const trimmedCmd = cmd.trim().toLowerCase();

    if (commands[trimmedCmd]) {
      const result = commands[trimmedCmd]();
      setCommandHistory(prev => [...prev, `> ${cmd}`, ...result]);
    } else {
      setCommandHistory(prev => [...prev, `> ${cmd}`, '  Error: Command not found. Type /help for available commands']);
    }

    setCurrentCommand('');
    setTimeout(() => {
      if (terminalRef.current) {
        terminalRef.current.scrollTop = terminalRef.current.scrollHeight;
      }
    }, 100);
  };

  const handleCommandKeyPress = (e) => {
    if (e.key === 'Enter') {
      if (currentCommand.trim()) {
        executeCommand(currentCommand);
      }
    }
  };

  return (
    <div className="space-y-2">
      {/* Main Workspace */}
      <textarea
        value={editablePrompt}
        onChange={(e) => setEditablePrompt(e.target.value)}
        className="w-full bg-slate-900 border border-purple-600/30 rounded p-3 text-xs text-purple-100 h-48 resize-none font-mono"
        placeholder="Workspace: Paste content, upload references, or use commands below..."
      />

      {/* Command Terminal */}
      <div className="bg-slate-950 border border-purple-600/20 rounded">
        <div className="flex items-center gap-2 px-3 py-1 bg-slate-900 rounded-t text-xs">
          <Terminal size={14} className="text-purple-400" />
          <span className="text-purple-300">Terminal</span>
          <button 
            onClick={() => setCommandMode(!commandMode)}
            className="ml-auto text-purple-400 hover:text-purple-300"
          >
            {commandMode ? 'Hide' : 'Show'}
          </button>
        </div>

        {commandMode && (
          <>
            {/* Command History */}
            <div 
              ref={terminalRef}
              className="h-20 overflow-y-auto p-2 text-xs font-mono text-green-300 bg-slate-950"
            >
              {commandHistory.map((line, i) => (
                <div key={i} className={line.startsWith('>') ? 'text-green-400' : 'text-green-300 pl-2'}>
                  {line}
                </div>
              ))}
            </div>

            {/* Command Input */}
            <div className="flex items-center gap-2 p-2 border-t border-purple-600/20">
              <span className="text-green-400 text-xs font-mono">$</span>
              <input
                type="text"
                value={currentCommand}
                onChange={(e) => setCurrentCommand(e.target.value)}
                onKeyPress={handleCommandKeyPress}
                className="flex-1 bg-transparent text-green-300 text-xs font-mono focus:outline-none"
                placeholder="Enter command... (try /help)"
              />
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default function EnhancedPromptGenerator() {
  const [apiKey, setApiKey] = useState('');
  const [showSettings, setShowSettings] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [viewMode, setViewMode] = useState('prompt'); // 'prompt' or 'output'
  const [generatedOutput, setGeneratedOutput] = useState('');
  const [editablePrompt, setEditablePrompt] = useState('');

  const [sections, setSections] = useState([
    { 
      id: 'role', 
      label: 'Role/Context', 
      value: '',
      placeholder: 'You are an expert [profession] with [experience] in [domain]...',
      subsections: [], 
      expanded: true,
      ref: useRef(null)
    },
    { 
      id: 'task', 
      label: 'Task/Objective', 
      value: '',
      placeholder: 'Your task is to [specific action] by [method] to achieve [goal]...',
      subsections: [], 
      expanded: true,
      ref: useRef(null)
    },
    { 
      id: 'process', 
      label: 'Process/Steps', 
      value: '',
      placeholder: '1. First step\n2. Second step\n3. Third step...',
      subsections: [], 
      expanded: true,
      ref: useRef(null)
    },
    { 
      id: 'constraints', 
      label: 'Rules/Constraints', 
      value: '',
      placeholder: '- Follow these guidelines\n- Avoid these patterns\n- Maintain this standard...',
      subsections: [], 
      expanded: true,
      ref: useRef(null)
    },
    { 
      id: 'output', 
      label: 'Output Format', 
      value: '',
      placeholder: 'Provide your response as [format] with [structure] including [elements]...',
      subsections: [], 
      expanded: true,
      ref: useRef(null)
    },
    { 
      id: 'examples', 
      label: 'Examples', 
      value: '',
      placeholder: 'Example input: [sample]\nExpected output: [result]\n\nExample input: [sample 2]\nExpected output: [result 2]...',
      subsections: [], 
      expanded: true,
      ref: useRef(null)
    }
  ]);

  const [activeSectionId, setActiveSectionId] = useState(null);
  const [syntaxAdvice, setSyntaxAdvice] = useState([]);
  const [liveSuggestions, setLiveSuggestions] = useState([]);
  const [optimizationScore, setOptimizationScore] = useState(0);
  const [scoreBreakdown, setScoreBreakdown] = useState({});

  // Update editable prompt when sections change
  useEffect(() => {
    setEditablePrompt(generatePrompt());
  }, [sections]);

  // Calculate optimization score
  useEffect(() => {
    calculateOptimization();
  }, [sections]);

  // Real-time syntax analysis with live suggestions
  useEffect(() => {
    if (activeSectionId) {
      const section = findSection(activeSectionId);
      if (section && section.value.length > 10) {
        analyzeSyntax(section);
        generateLiveSuggestions(section);
      }
    }
  }, [activeSectionId, sections]);

  const findSection = (id) => {
    for (let section of sections) {
      if (section.id === id) return section;
      const subsection = section.subsections.find(s => s.id === id);
      if (subsection) return subsection;
    }
    return null;
  };

  const calculateOptimization = () => {
    let scores = {
      completeness: 0,
      clarity: 0,
      structure: 0,
      specificity: 0,
      examples: 0
    };

    // Completeness (25 points)
    const filledSections = sections.filter(s => s.value.trim().length > 0).length;
    scores.completeness = (filledSections / sections.length) * 25;

    // Clarity (25 points) - check for vague words
    const vagueWords = ['thing', 'stuff', 'maybe', 'somehow', 'something'];
    let totalWords = 0;
    let vagueCount = 0;

    sections.forEach(s => {
      const words = s.value.toLowerCase().split(/\s+/);
      totalWords += words.length;
      vagueCount += words.filter(w => vagueWords.includes(w)).length;
    });

    scores.clarity = totalWords > 0 ? Math.max(0, 25 - (vagueCount * 5)) : 0;

    // Structure (20 points) - check for formatting
    let structurePoints = 0;
    sections.forEach(s => {
      if (s.value.includes('\n')) structurePoints += 2;
      if (s.value.match(/^[-*•]/m)) structurePoints += 2;
      if (s.value.match(/^\d+\./m)) structurePoints += 2;
    });
    scores.structure = Math.min(20, structurePoints);

    // Specificity (20 points) - length and detail
    const avgLength = sections.reduce((acc, s) => acc + s.value.length, 0) / sections.length;
    scores.specificity = Math.min(20, (avgLength / 50) * 20);

    // Examples (10 points)
    const examplesSection = sections.find(s => s.id === 'examples');
    if (examplesSection && examplesSection.value.length > 50) {
      scores.examples = 10;
    }

    const total = Object.values(scores).reduce((a, b) => a + b, 0);
    setOptimizationScore(Math.round(total));
    setScoreBreakdown(scores);
  };

  const analyzeSyntax = (section) => {
    const advice = [];
    const text = section.value.toLowerCase();

    if (section.id === 'role') {
      if (!text.includes('you are')) {
        advice.push({ type: 'tip', text: 'Start with "You are..." to establish clear identity' });
      }
      if (text.length < 30) {
        advice.push({ type: 'warning', text: 'Add more context about expertise and background' });
      }
    }

    if (section.id === 'task') {
      if (!text.match(/\b(analyze|create|generate|write|explain|solve)\b/)) {
        advice.push({ type: 'tip', text: 'Use action verbs: analyze, create, generate, explain' });
      }
    }

    if (section.id === 'process') {
      if (!text.match(/^\d+\./m) && !text.match(/^[-*]/m)) {
        advice.push({ type: 'tip', text: 'Use numbered steps or bullet points for clarity' });
      }
    }

    if (section.id === 'constraints') {
      if (!text.includes('-') && !text.includes('•')) {
        advice.push({ type: 'tip', text: 'List constraints as bullet points for readability' });
      }
    }

    if (section.id === 'output') {
      if (!text.match(/\b(format|structure|markdown|json|table)\b/)) {
        advice.push({ type: 'tip', text: 'Specify output format: markdown, JSON, table, etc.' });
      }
    }

    const vagueWords = ['thing', 'stuff', 'maybe', 'somehow'];
    vagueWords.forEach(word => {
      if (text.includes(word)) {
        advice.push({ type: 'warning', text: `Avoid vague language like "${word}"` });
      }
    });

    setSyntaxAdvice(advice);
  };

  const generateLiveSuggestions = async (section) => {
    if (!apiKey) {
      // Fallback to mock suggestions if no API key
      const suggestions = [];
      if (section.value.length > 20) {
        suggestions.push({
          improved: `Enhanced version: ${section.value.substring(0, 50)}...`,
          reason: 'Add API key in settings for real suggestions'
        });
      }
      setLiveSuggestions(suggestions);
      return;
    }

    try {
      const response = await fetch('http://localhost:3001/api/suggestions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          apiKey,
          text: section.value,
          sectionType: section.id
        })
      });

      const data = await response.json();

      if (data.success && data.data.suggestions) {
        setLiveSuggestions(data.data.suggestions.map(s => ({
          improved: s.improved,
          reason: s.reason
        })));
      } else {
        setLiveSuggestions([]);
      }
    } catch (error) {
      console.error('Suggestions error:', error);
      setLiveSuggestions([]);
    }
  };

  const applySuggestion = (suggestion) => {
    const section = findSection(activeSectionId);
    if (section) {
      updateSection(activeSectionId, suggestion.improved);
    }
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (!apiKey) {
      alert('Please add your Anthropic API key in settings first.');
      return;
    }

    setIsGenerating(true);

    try {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('apiKey', apiKey);

      const response = await fetch('http://localhost:3001/api/upload', {
        method: 'POST',
        body: formData
      });

      const data = await response.json();

      if (data.success && data.data) {
        // Update sections with extracted data
        setSections(sections.map(s => ({
          ...s,
          value: data.data[s.id] || s.value
        })));

        setCommandHistory(prev => [...prev, 
          '> File uploaded and analyzed successfully',
          `  ✓ Extracted content for ${Object.keys(data.data).length} sections`
        ]);
      } else {
        alert('Error analyzing file: ' + (data.error || 'Unknown error'));
      }

    } catch (error) {
      alert('Error uploading file: ' + error.message);
    } finally {
      setIsGenerating(false);
    }
  };

  const smartSubdivide = async (sectionId) => {
    const section = findSection(sectionId);
    if (!section || !section.value) return;

    if (!apiKey) {
      // Fallback to simple text splitting if no API key
      const text = section.value;
      let chunks = [];

      if (text.includes('\n\n')) {
        chunks = text.split('\n\n').map(chunk => chunk.trim()).filter(chunk => chunk.length > 0);
      } else if (text.match(/^\d+\./m)) {
        chunks = text.split(/\n(?=\d+\.)/g).map(chunk => chunk.trim()).filter(chunk => chunk.length > 0);
      } else if (text.match(/^[-*•]/m)) {
        chunks = text.split(/\n(?=[-*•])/g).map(chunk => chunk.trim()).filter(chunk => chunk.length > 0);
      } else {
        chunks = text.split(/\. /).map(chunk => chunk.trim() + (chunk.endsWith('.') ? '' : '.')).filter(chunk => chunk.length > 5);
      }

      if (chunks.length > 1) {
        setSections(sections.map(s => {
          if (s.id === sectionId) {
            return {
              ...s,
              value: '',
              subsections: chunks.map((chunk, index) => ({
                id: `${sectionId}-chunk-${Date.now()}-${index}`,
                label: `Part ${index + 1}`,
                value: chunk,
                subsections: []
              }))
            };
          }
          return s;
        }));
      }
      return;
    }

    try {
      setIsGenerating(true);
      const response = await fetch('http://localhost:3001/api/subdivide', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          apiKey,
          text: section.value,
          sectionType: section.id
        })
      });

      const data = await response.json();

      if (data.success && data.data.options) {
        // Show options to user (for now, auto-select first option)
        const selectedOption = data.data.options[0];

        setSections(sections.map(s => {
          if (s.id === sectionId) {
            return {
              ...s,
              value: '',
              subsections: selectedOption.chunks.map((chunk, index) => ({
                id: `${sectionId}-chunk-${Date.now()}-${index}`,
                label: `${selectedOption.name} ${index + 1}`,
                value: chunk,
                subsections: []
              }))
            };
          }
          return s;
        }));
      }
    } catch (error) {
      console.error('Subdivide error:', error);
    } finally {
      setIsGenerating(false);
    }
  };

  const updateSection = (id, value) => {
    setSections(sections.map(section => {
      if (section.id === id) {
        return { ...section, value };
      }
      if (section.subsections.length > 0) {
        return {
          ...section,
          subsections: section.subsections.map(sub =>
            sub.id === id ? { ...sub, value } : sub
          )
        };
      }
      return section;
    }));
  };

  const handleKeyPress = (e, sectionId) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      // Find next section
      const currentIndex = sections.findIndex(s => s.id === sectionId);
      const nextSection = sections[currentIndex + 1];

      if (nextSection && nextSection.ref.current) {
        nextSection.ref.current.focus();
      }
    }
  };

  const toggleSection = (sectionId) => {
    setSections(sections.map(s => 
      s.id === sectionId ? { ...s, expanded: !s.expanded } : s
    ));
  };

  const generatePrompt = () => {
    const parts = sections
      .filter(s => s.value.trim() || s.subsections.length > 0)
      .map(s => {
        let content = s.value ? `# ${s.label}\n${s.value}` : `# ${s.label}`;
        if (s.subsections.length > 0) {
          content += s.value ? '\n\n' : '\n';
          content += s.subsections
            .filter(sub => sub.value.trim())
            .map(sub => `## ${sub.label}\n${sub.value}`)
            .join('\n\n');
        }
        return content;
      })
      .join('\n\n');
    return parts || '# Empty Prompt\nAdd content to your sections to generate a prompt.';
  };

  const generateMockOutput = async () => {
    // Mock AI output generation for demo
    setIsGenerating(true);

    setTimeout(() => {
      const mockOutput = `Based on your prompt structure, here's what an AI response might look like:

**Analysis Results:**
- Identified 3 key areas for improvement
- Found optimal solution path
- Generated actionable recommendations

**Recommendations:**
1. Implement structured approach
2. Focus on user experience
3. Iterate based on feedback

**Conclusion:**
The proposed solution addresses the core requirements while maintaining flexibility for future enhancements.`;

      setGeneratedOutput(mockOutput);
      setIsGenerating(false);
    }, 1500);
  };

  const handleCopy = () => {
    const textToCopy = viewMode === 'prompt' ? editablePrompt : generatedOutput;
    navigator.clipboard.writeText(textToCopy);
  };

  const getScoreColor = (score) => {
    if (score >= 80) return 'text-green-400';
    if (score >= 60) return 'text-yellow-400';
    return 'text-red-400';
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900 text-white p-4">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-3xl font-bold">Enhanced Prompt Generator</h1>
            <p className="text-purple-300 text-sm">Dynamic structure with smart features</p>
          </div>
          <div className="flex gap-2">
            <label className="cursor-pointer bg-purple-600 hover:bg-purple-700 px-4 py-2 rounded transition-colors flex items-center gap-2">
              <Upload size={18} />
              Upload
              <input type="file" accept=".txt,.pdf" onChange={handleFileUpload} className="hidden" />
            </label>
            <button onClick={() => setShowSettings(!showSettings)} className="p-2 bg-purple-600 hover:bg-purple-700 rounded transition-colors">
              <Settings size={20} />
            </button>
          </div>
        </div>

        {/* Settings */}
        {showSettings && (
          <div className="bg-slate-800/50 rounded p-4 mb-4 border border-purple-500/30">
            <h3 className="font-semibold mb-2">API Settings</h3>
            <input
              type="password"
              value={apiKey}
              onChange={(e) => setApiKey(e.target.value)}
              placeholder="sk-ant-... (for AI features)"
              className="w-full bg-slate-900 border border-purple-500/50 rounded px-3 py-2 text-sm"
            />
          </div>
        )}

        {/* Main Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
          {/* Sections Grid (3 columns on left) */}
          <div className="lg:col-span-3 grid grid-cols-1 md:grid-cols-2 gap-3">
            {sections.map((section) => (
              <div key={section.id} className="bg-slate-800/50 rounded p-3 border border-purple-500/20">
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <button onClick={() => toggleSection(section.id)} className="text-purple-400">
                      {section.expanded ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
                    </button>
                    <label className="text-sm font-semibold text-purple-300">{section.label}</label>
                  </div>
                  <div className="flex gap-1">
                    <button
                      onClick={() => smartSubdivide(section.id)}
                      disabled={!section.value}
                      className="p-1 bg-purple-600/50 hover:bg-purple-600 rounded transition-colors disabled:opacity-30"
                      title="Smart subdivide text"
                    >
                      <Plus size={14} />
                    </button>
                    <button
                      disabled={true}
                      className="p-1 bg-purple-600/30 rounded opacity-50"
                      title="AI generation (needs backend)"
                    >
                      <Sparkles size={14} />
                    </button>
                  </div>
                </div>

                {section.expanded && (
                  <>
                    <textarea
                      ref={section.ref}
                      value={section.value}
                      onChange={(e) => updateSection(section.id, e.target.value)}
                      onFocus={() => setActiveSectionId(section.id)}
                      onKeyPress={(e) => handleKeyPress(e, section.id)}
                      placeholder={section.placeholder}
                      className="w-full bg-slate-900 border border-purple-600/20 rounded px-2 py-2 text-sm h-24 resize-none focus:border-purple-400 focus:outline-none transition-colors placeholder-slate-500"
                    />

                    {section.subsections.map((sub) => (
                      <div key={sub.id} className="mt-2 ml-4 border-l-2 border-purple-500/30 pl-3">
                        <div className="flex items-center justify-between mb-1">
                          <label className="text-xs text-purple-400">{sub.label}</label>
                          <button
                            disabled={true}
                            className="p-1 bg-purple-600/20 rounded opacity-50"
                          >
                            <Sparkles size={12} />
                          </button>
                        </div>
                        <textarea
                          value={sub.value}
                          onChange={(e) => updateSection(sub.id, e.target.value)}
                          onFocus={() => setActiveSectionId(sub.id)}
                          className="w-full bg-slate-900 border border-purple-600/20 rounded px-2 py-1 text-sm h-16 resize-none"
                        />
                      </div>
                    ))}
                  </>
                )}
              </div>
            ))}
          </div>

          {/* Right Sidebar */}
          <div className="space-y-3">
            {/* Optimization Score */}
            <div className="bg-slate-800/50 rounded p-3 border border-purple-500/30">
              <div className="flex items-center gap-2 mb-2">
                <TrendingUp size={18} className="text-purple-400" />
                <h3 className="text-sm font-semibold">Optimization</h3>
              </div>
              <div className={`text-3xl font-bold ${getScoreColor(optimizationScore)} mb-2`}>
                {optimizationScore}%
              </div>
              <div className="space-y-1 text-xs">
                <div className="flex justify-between">
                  <span className="text-purple-300">Completeness</span>
                  <span>{Math.round(scoreBreakdown.completeness || 0)}%</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-purple-300">Clarity</span>
                  <span>{Math.round(scoreBreakdown.clarity || 0)}%</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-purple-300">Structure</span>
                  <span>{Math.round(scoreBreakdown.structure || 0)}%</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-purple-300">Specificity</span>
                  <span>{Math.round(scoreBreakdown.specificity || 0)}%</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-purple-300">Examples</span>
                  <span>{Math.round(scoreBreakdown.examples || 0)}%</span>
                </div>
              </div>
            </div>

            {/* Live Suggestions */}
            <div className="bg-slate-800/50 rounded p-3 border border-purple-500/30">
              <h3 className="text-sm font-semibold mb-2 text-purple-300">Live Suggestions</h3>
              {liveSuggestions.length > 0 ? (
                <div className="space-y-2">
                  {liveSuggestions.map((suggestion, i) => (
                    <div key={i} className="bg-blue-900/30 rounded p-2 border border-blue-500/30">
                      <p className="text-xs text-blue-300 mb-1">{suggestion.reason}</p>
                      <p className="text-xs text-blue-200 mb-2 italic">"{suggestion.improved.substring(0, 60)}..."</p>
                      <button 
                        onClick={() => applySuggestion(suggestion)}
                        className="text-xs bg-blue-600 hover:bg-blue-700 px-2 py-1 rounded flex items-center gap-1"
                      >
                        <Check size={12} />
                        Apply
                      </button>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="space-y-2">
                  {syntaxAdvice.map((advice, i) => (
                    <div key={i} className={`text-xs p-2 rounded ${advice.type === 'warning' ? 'bg-yellow-900/30 text-yellow-300' : 'bg-blue-900/30 text-blue-300'}`}>
                      {advice.text}
                    </div>
                  ))}
                  {syntaxAdvice.length === 0 && (
                    <p className="text-xs text-purple-400">Click a section to see suggestions</p>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Terminal-Style Workspace */}
        <div className="mt-4 bg-slate-800/50 rounded p-3 border border-purple-500/30">
          <div className="flex justify-between items-center mb-2">
            <div className="flex items-center gap-3">
              <h3 className="text-sm font-semibold">Terminal Workspace</h3>
              <div className="flex items-center gap-2">
                <span className="text-xs">Workspace</span>
                <button 
                  onClick={() => setViewMode(viewMode === 'prompt' ? 'output' : 'prompt')}
                  className="text-purple-400 hover:text-purple-300"
                >
                  {viewMode === 'prompt' ? <ToggleLeft size={20} /> : <ToggleRight size={20} />}
                </button>
                <span className="text-xs">Output</span>
              </div>
            </div>
            <div className="flex gap-2">
              {viewMode === 'output' && !generatedOutput && (
                <button 
                  onClick={generateMockOutput}
                  disabled={isGenerating}
                  className="text-xs bg-green-600 hover:bg-green-700 disabled:bg-slate-600 px-3 py-1 rounded flex items-center gap-1"
                >
                  <Wand2 size={12} />
                  {isGenerating ? 'Generating...' : 'Generate Output'}
                </button>
              )}
              <button onClick={handleCopy} className="flex items-center gap-1 bg-purple-600 hover:bg-purple-700 px-3 py-1 rounded text-xs transition-colors">
                {viewMode === 'prompt' ? <Upload size={12} /> : <Copy size={12} />}
                {viewMode === 'prompt' ? 'Upload/Paste' : 'Copy Output'}
              </button>
            </div>
          </div>

          {viewMode === 'prompt' ? (
            <TerminalWorkspace 
              editablePrompt={editablePrompt}
              setEditablePrompt={setEditablePrompt}
              sections={sections}
              setSections={setSections}
            />
          ) : (
            <div className="bg-slate-900 border border-purple-600/30 rounded p-3 text-xs text-purple-100 h-64 overflow-y-auto">
              {generatedOutput ? (
                <pre className="whitespace-pre-wrap">{generatedOutput}</pre>
              ) : (
                <div className="flex items-center justify-center h-full text-purple-400">
                  Click "Generate Output" to see what this prompt would produce
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
